<!DOCTYPE html>
<html lang="zh">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>双AI对手乒乓球大战</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body {
    background: #0a0a2e;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100vh;
    font-family: 'Courier New', monospace;
    overflow: hidden;
}
canvas {
    border: 2px solid #00ffff;
    box-shadow: 0 0 30px rgba(0, 255, 255, 0.3);
    border-radius: 4px;
}
</style>
</head>
<body>
<canvas id="gameCanvas"></canvas>
<script>
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

canvas.width = 900;
canvas.height = 600;

// 游戏状态
let gameState = 'menu'; // menu, playing, paused, gameover
let winner = '';

// 粒子系统
let particles = [];
let trails = [];

// 玩家（左侧）
const player = {
    x: 20,
    y: canvas.height / 2 - 50,
    width: 12,
    height: 100,
    speed: 7,
    score: 0,
    color: '#00ff88',
    glowColor: 'rgba(0, 255, 136, 0.5)',
    name: '玩家',
    moveUp: false,
    moveDown: false,
    targetY: null
};

// AI对手1（右上）
const ai1 = {
    x: canvas.width - 32,
    y: canvas.height / 4 - 40,
    width: 12,
    height: 80,
    speed: 4.5,
    score: 0,
    color: '#ff4466',
    glowColor: 'rgba(255, 68, 102, 0.5)',
    name: 'AI-α',
    difficulty: 0.85,
    reactionDelay: 0,
    predictedY: 0
};

// AI对手2（右下）
const ai2 = {
    x: canvas.width - 32,
    y: (canvas.height * 3) / 4 - 40,
    width: 12,
    height: 80,
    speed: 5.2,
    score: 0,
    color: '#ffaa00',
    glowColor: 'rgba(255, 170, 0, 0.5)',
    name: 'AI-β',
    difficulty: 0.92,
    reactionDelay: 0,
    predictedY: 0
};

// 球
const ball = {
    x: canvas.width / 2,
    y: canvas.height / 2,
    radius: 8,
    speedX: 5,
    speedY: 3,
    baseSpeed: 5,
    maxSpeed: 12,
    color: '#ffffff',
    trail: []
};

// 能力道具
let powerups = [];
let powerupTimer = 0;
const POWERUP_INTERVAL = 600; // 每600帧生成一个道具

// 活跃效果
let activeEffects = {
    player: { type: null, timer: 0 },
    ai1: { type: null, timer: 0 },
    ai2: { type: null, timer: 0 }
};

// 屏幕震动
let screenShake = { x: 0, y: 0, intensity: 0 };

// 连击系统
let combo = 0;
let comboTimer = 0;
let lastHitter = '';

// 浮动文字
let floatingTexts = [];

// 星空背景
let stars = [];
for (let i = 0; i < 100; i++) {
    stars.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 2 + 0.5,
        speed: Math.random() * 0.5 + 0.1,
        brightness: Math.random()
    });
}

// 键盘控制
const keys = {};
document.addEventListener('keydown', (e) => {
    keys[e.key] = true;
    if (e.key === ' ' || e.key === 'Enter') {
        if (gameState === 'menu') {
            gameState = 'playing';
            resetBall();
        } else if (gameState === 'gameover') {
            resetGame();
            gameState = 'playing';
        } else if (gameState === 'playing') {
            // gameState = 'paused';
        } else if (gameState === 'paused') {
            gameState = 'playing';
        }
    }
    if (e.key === 'p' || e.key === 'P') {
        if (gameState === 'playing') gameState = 'paused';
        else if (gameState === 'paused') gameState = 'playing';
    }
});
document.addEventListener('keyup', (e) => { keys[e.key] = false; });

// 鼠标/触摸控制
canvas.addEventListener('mousemove', (e) => {
    const rect = canvas.getBoundingClientRect();
    player.targetY = (e.clientY - rect.top) * (canvas.height / rect.height) - player.height / 2;
});

canvas.addEventListener('click', () => {
    if (gameState === 'menu') {
        gameState = 'playing';
        resetBall();
    } else if (gameState === 'gameover') {
        resetGame();
        gameState = 'playing';
    }
});

function createParticles(x, y, color, count = 15, spread = 5) {
    for (let i = 0; i < count; i++) {
        particles.push({
            x: x,
            y: y,
            vx: (Math.random() - 0.5) * spread * 2,
            vy: (Math.random() - 0.5) * spread * 2,
            life: 1,
            decay: Math.random() * 0.03 + 0.02,
            size: Math.random() * 4 + 2,
            color: color
        });
    }
}

function createFloatingText(x, y, text, color, size = 20) {
    floatingTexts.push({
        x, y, text, color, size,
        life: 1,
        vy: -2
    });
}

function createPowerup() {
    const types = ['speed', 'big', 'multi', 'slow'];
    const type = types[Math.floor(Math.random() * types.length)];
    const colors = { speed: '#00ffff', big: '#ff00ff', multi: '#ffff00', slow: '#88ff88' };
    const labels = { speed: '⚡', big: '🔷', multi: '✦', slow: '❄' };

    powerups.push({
        x: canvas.width * 0.2 + Math.random() * canvas.width * 0.6,
        y: canvas.height * 0.1 + Math.random() * canvas.height * 0.8,
        radius: 15,
        type: type,
        color: colors[type],
        label: labels[type],
        life: 1,
        pulse: 0,
        collected: false
    });
}

function resetBall() {
    ball.x = canvas.width / 2;
    ball.y = canvas.height / 2;
    const angle = (Math.random() - 0.5) * Math.PI / 3;
    const direction = Math.random() > 0.5 ? 1 : -1;
    ball.speedX = Math.cos(angle) * ball.baseSpeed * direction;
    ball.speedY = Math.sin(angle) * ball.baseSpeed;
    ball.trail = [];
    combo = 0;
}

function resetGame() {
    player.score = 0;
    ai1.score = 0;
    ai2.score = 0;
    player.y = canvas.height / 2 - player.height / 2;
    player.height = 100;
    ai1.y = canvas.height / 4 - ai1.height / 2;
    ai1.height = 80;
    ai2.y = (canvas.height * 3) / 4 - ai2.height / 2;
    ai2.height = 80;
    powerups = [];
    particles = [];
    floatingTexts = [];
    activeEffects = {
        player: { type: null, timer: 0 },
        ai1: { type: null, timer: 0 },
        ai2: { type: null, timer: 0 }
    };
    combo = 0;
    comboTimer = 0;
    resetBall();
}

function predictBallY(paddle, ballObj) {
    if (ballObj.speedX <= 0 && paddle.x > canvas.width / 2) return ballObj.y;
    if (ballObj.speedX >= 0 && paddle.x < canvas.width / 2) return ballObj.y;

    let simX = ballObj.x;
    let simY = ballObj.y;
    let simVX = ballObj.speedX;
    let simVY = ballObj.speedY;

    let steps = 0;
    while (steps < 200) {
        simX += simVX;
        simY += simVY;

        if (simY <= ballObj.radius || simY >= canvas.height - ballObj.radius) {
            simVY = -simVY;
        }

        if ((paddle.x > canvas.width / 2 && simX >= paddle.x) ||
            (paddle.x < canvas.width / 2 && simX <= paddle.x + paddle.width)) {
            return simY;
        }
        steps++;
    }
    return canvas.height / 2;
}

function updateAI(aiPaddle, ballObj) {
    // 预测球的位置
    if (Math.random() < 0.05) {
        aiPaddle.predictedY = predictBallY(aiPaddle, ballObj);
        // 添加一些不完美性
        aiPaddle.predictedY += (Math.random() - 0.5) * (1 - aiPaddle.difficulty) * 150;
    }

    let targetY = aiPaddle.predictedY - aiPaddle.height / 2;

    // 球远离时回到中心区域
    if (ballObj.speedX < 0) {
        const centerZone = aiPaddle === ai1 ? canvas.height / 4 : (canvas.height * 3) / 4;
        targetY = centerZone - aiPaddle.height / 2 + (Math.random() - 0.5) * 30;
    }

    const diff = targetY - aiPaddle.y;
    const effectiveSpeed = aiPaddle.speed * aiPaddle.difficulty;

    if (Math.abs(diff) > 3) {
        if (diff > 0) aiPaddle.y += Math.min(effectiveSpeed, diff);
        else aiPaddle.y += Math.max(-effectiveSpeed, diff);
    }

    // AI之间的协作 - 避免重叠
    if (aiPaddle === ai1 && ai1.y + ai1.height > ai2.y - 10) {
        ai1.y = ai2.y - ai1.height - 10;
    }
    if (aiPaddle === ai2 && ai2.y < ai1.y + ai1.height + 10) {
        ai2.y = ai1.y + ai1.height + 10;
    }

    // 边界限制
    aiPaddle.y = Math.max(0, Math.min(canvas.height - aiPaddle.height, aiPaddle.y));
}

function checkPaddleCollision(paddle, ballObj, isPlayer) {
    if (ballObj.x - ballObj.radius < paddle.x + paddle.width &&
        ballObj.x + ballObj.radius > paddle.x &&
        ballObj.y + ballObj.radius > paddle.y &&
        ballObj.y - ballObj.radius < paddle.y + paddle.height) {

        // 计算反弹角度
        const hitPos = (ballObj.y - paddle.y) / paddle.height;
        const angle = (hitPos - 0.5) * Math.PI * 0.7;

        const speed = Math.min(Math.sqrt(ballObj.speedX ** 2 + ballObj.speedY ** 2) + 0.3, ball.maxSpeed);

        if (isPlayer) {
            ballObj.speedX = Math.abs(Math.cos(angle) * speed);
        } else {
            ballObj.speedX = -Math.abs(Math.cos(angle) * speed);
        }
        ballObj.speedY = Math.sin(angle) * speed;

        // 确保球不卡在挡板里
        if (isPlayer) {
            ballObj.x = paddle.x + paddle.width + ballObj.radius;
        } else {
            ballObj.x = paddle.x - ballObj.radius;
        }

        // 粒子效果
        createParticles(ballObj.x, ballObj.y, paddle.color, 20, 6);

        // 屏幕震动
        screenShake.intensity = 3;

        // 连击
        const hitterName = paddle.name;
        if (lastHitter === hitterName) {
            combo++;
            if (combo > 1) {
                createFloatingText(ballObj.x, ballObj.y - 20, `${combo}连击!`, '#ffff00', 16 + combo * 2);
            }
        } else {
            combo = 1;
            lastHitter = hitterName;
        }
        comboTimer = 180;

        return true;
    }
    return false;
}

function update() {
    if (gameState !== 'playing') return;

    // 更新玩家位置
    if (player.targetY !== null) {
        const diff = player.targetY - player.y;
        player.y += diff * 0.15;
    }
    if (keys['w'] || keys['W'] || keys['ArrowUp']) player.y -= player.speed;
    if (keys['s'] || keys['S'] || keys['ArrowDown']) player.y += player.speed;
    player.y = Math.max(0, Math.min(canvas.height - player.height, player.y));

    // 更新AI
    updateAI(ai1, ball);
    updateAI(ai2, ball);

    // 更新球轨迹
    ball.trail.push({ x: ball.x, y: ball.y });
    if (ball.trail.length > 15) ball.trail.shift();

    // 更新球位置
    ball.x += ball.speedX;
    ball.y += ball.speedY;

    // 上下边界反弹
    if (ball.y - ball.radius <= 0) {
        ball.y = ball.radius;
        ball.speedY = Math.abs(ball.speedY);
        createParticles(ball.x, ball.y, '#00ffff', 8, 3);
    }
    if (ball.y + ball.radius >= canvas.height) {
        ball.y = canvas.height - ball.radius;
        ball.speedY = -Math.abs(ball.speedY);
        createParticles(ball.x, ball.y, '#00ffff', 8, 3);
    }

    // 挡板碰撞
    checkPaddleCollision(player, ball, true);

    // AI挡板碰撞 - 检测哪个AI更近
    const ai1Dist = Math.abs(ball.y - (ai1.y + ai1.height / 2));
    const ai2Dist = Math.abs(ball.y - (ai2.y + ai2.height / 2));

    if (!checkPaddleCollision(ai1, ball, false)) {
        checkPaddleCollision(ai2, ball, false);
    }

    // 道具碰撞检测
    powerups.forEach((p, index) => {
        if (p.collected) return;
        const dx = ball.x - p.x;
        const dy = ball.y - p.y;
        if (Math.sqrt(dx * dx + dy * dy) < ball.radius + p.radius) {
            p.collected = true;
            createParticles(p.x, p.y, p.color, 25, 8);
            createFloatingText(p.x, p.y - 20, p.type.toUpperCase() + '!', p.color, 24);

            // 应用效果给最后击球的人
            let target = lastHitter === '玩家' ? 'player' : 
                         lastHitter === 'AI-α' ? 'ai1' : 'ai2';

            applyPowerup(target, p.type);
        }
    });
    powerups = powerups.filter(p => !p.collected);

    // 道具生成
    powerupTimer++;
    if (powerupTimer >= POWERUP_INTERVAL) {
        powerupTimer = 0;
        if (powerups.length < 3) createPowerup();
    }

    // 更新道具动画
    powerups.forEach(p => {
        p.pulse += 0.05;
    });

    // 更新效果计时器
    for (let key in activeEffects) {
        if (activeEffects[key].timer > 0) {
            activeEffects[key].timer--;
            if (activeEffects[key].timer <= 0) {
                removePowerup(key, activeEffects[key].type);
                activeEffects[key].type = null;
            }
        }
    }

    // 得分判定
    if (ball.x < -20) {
        // AI得分 - 两个AI各得1分
        ai1.score++;
        ai2.score++;
        createParticles(0, ball.y, '#ff4466', 30, 10);
        createFloatingText(canvas.width / 4, canvas.height / 2, 'AI 得分!', '#ff4466', 30);
        screenShake.intensity = 8;
        checkGameOver();
        if (gameState === 'playing') resetBall();
    }
    if (ball.x > canvas.width + 20) {
        // 玩家得分
        player.score += 2;
        createParticles(canvas.width, ball.y, '#00ff88', 30, 10);
        createFloatingText(canvas.width * 3 / 4, canvas.height / 2, '得分 +2!', '#00ff88', 30);
        screenShake.intensity = 8;
        checkGameOver();
        if (gameState === 'playing') resetBall();
    }

    // 连击计时器
    if (comboTimer > 0) comboTimer--;
    if (comboTimer <= 0) combo = 0;

    // 更新粒子
    particles.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.life -= p.decay;
        p.vx *= 0.98;
        p.vy *= 0.98;
    });
    particles = particles.filter(p => p.life > 0);

    // 更新浮动文字
    floatingTexts.forEach(t => {
        t.y += t.vy;
        t.life -= 0.015;
    });
    floatingTexts = floatingTexts.filter(t => t.life > 0);

    // 更新屏幕震动
    if (screenShake.intensity > 0) {
        screenShake.x = (Math.random() - 0.5) * screenShake.intensity;
        screenShake.y = (Math.random() - 0.5) * screenShake.intensity;
        screenShake.intensity *= 0.9;
        if (screenShake.intensity < 0.5) {
            screenShake.intensity = 0;
            screenShake.x = 0;
            screenShake.y = 0;
        }
    }

    // 更新星星
    stars.forEach(s => {
        s.brightness = 0.3 + Math.sin(Date.now() * 0.001 * s.speed + s.x) * 0.7;
    });
}

function applyPowerup(target, type) {
    const paddle = target === 'player' ? player : target === 'ai1' ? ai1 : ai2;

    // 移除之前的效果
    if (activeEffects[target].type) {
        removePowerup(target, activeEffects[target].type);
    }

    activeEffects[target] = { type: type, timer: 300 };

    switch (type) {
        case 'speed':
            paddle.speed *= 1.5;
            break;
        case 'big':
            paddle.height *= 1.5;
            break;
        case 'slow':
            // 减慢对手
            if (target === 'player') {
                ai1.speed *= 0.6;
                ai2.speed *= 0.6;
            } else {
                player.speed *= 0.6;
            }
            break;
        case 'multi':
            ball.speedX *= 1.3;
            ball.speedY *= 1.3;
            break;
    }
}

function removePowerup(target, type) {
    const paddle = target === 'player' ? player : target === 'ai1' ? ai1 : ai2;

    switch (type) {
        case 'speed':
            paddle.speed = target === 'player' ? 7 : target === 'ai1' ? 4.5 : 5.2;
            break;
        case 'big':
            paddle.height = target === 'player' ? 100 : 80;
            paddle.y = Math.min(paddle.y, canvas.height - paddle.height);
            break;
        case 'slow':
            if (target === 'player') {
                ai1.speed = 4.5;
                ai2.speed = 5.2;
            } else {
                player.speed = 7;
            }
            break;
    }
}

function checkGameOver() {
    const winScore = 15;
    if (player.score >= winScore) {
        gameState = 'gameover';
        winner = '🏆 玩家获胜！';
    } else if (ai1.score >= winScore || ai2.score >= winScore) {
        gameState = 'gameover';
        if (ai1.score > ai2.score) winner = '💀 AI-α 获胜！';
        else if (ai2.score > ai1.score) winner = '💀 AI-β 获胜！';
        else winner = '💀 AI联盟获胜！';
    }
}

function drawGlowRect(x, y, w, h, color, glowColor) {
    ctx.shadowColor = color;
    ctx.shadowBlur = 20;
    ctx.fillStyle = glowColor;
    ctx.fillRect(x - 3, y - 3, w + 6, h + 6);
    ctx.shadowBlur = 0;

    ctx.fillStyle = color;
    ctx.fillRect(x, y, w, h);

    // 高光
    const gradient = ctx.createLinearGradient(x, y, x + w, y);
    gradient.addColorStop(0, 'rgba(255,255,255,0.3)');
    gradient.addColorStop(1, 'rgba(255,255,255,0)');
    ctx.fillStyle = gradient;
    ctx.fillRect(x, y, w, h);
}

function drawBall() {
    // 轨迹
    ball.trail.forEach((t, i) => {
        const alpha = i / ball.trail.length * 0.5;
        const size = ball.radius * (i / ball.trail.length);
        ctx.beginPath();
        ctx.arc(t.x, t.y, size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
        ctx.fill();
    });

    // 球本体发光
    ctx.shadowColor = '#ffffff';
    ctx.shadowBlur = 25;
    ctx.beginPath();
    ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
    ctx.fillStyle = '#ffffff';
    ctx.fill();
    ctx.shadowBlur = 0;

    // 球内部渐变
    const grad = ctx.createRadialGradient(ball.x - 2, ball.y - 2, 0, ball.x, ball.y, ball.radius);
    grad.addColorStop(0, '#ffffff');
    grad.addColorStop(1, '#aaddff');
    ctx.beginPath();
    ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
}

function drawField() {
    // 背景渐变
    const bgGrad = ctx.createRadialGradient(canvas.width / 2, canvas.height / 2, 0, canvas.width / 2, canvas.height / 2, canvas.width / 2);
    bgGrad.addColorStop(0, '#0d1b3e');
    bgGrad.addColorStop(1, '#050a1a');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 星空
    stars.forEach(s => {
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(200, 220, 255, ${s.brightness * 0.5})`;
        ctx.fill();
    });

    // 中线
    ctx.setLineDash([10, 10]);
    ctx.strokeStyle = 'rgba(100, 150, 255, 0.2)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(canvas.width / 2, 0);
    ctx.lineTo(canvas.width / 2, canvas.height);
    ctx.stroke();
    ctx.setLineDash([]);

    // 右侧AI区域分隔线
    ctx.setLineDash([5, 15]);
    ctx.strokeStyle = 'rgba(255, 100, 100, 0.15)';
    ctx.beginPath();
    ctx.moveTo(canvas.width / 2, canvas.height / 2);
    ctx.lineTo(canvas.width, canvas.height / 2);
    ctx.stroke();
    ctx.setLineDash([]);

    // 中心圆
    ctx.beginPath();
    ctx.arc(canvas.width / 2, canvas.height / 2, 50, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(100, 150, 255, 0.15)';
    ctx.lineWidth = 1;
    ctx.stroke();
}

function drawScoreboard() {
    // 玩家分数
    ctx.font = 'bold 48px "Courier New"';
    ctx.textAlign = 'center';

    ctx.shadowColor = player.color;
    ctx.shadowBlur = 15;
    ctx.fillStyle = player.color;
    ctx.fillText(player.score, canvas.width / 4, 60);
    ctx.shadowBlur = 0;

    ctx.font = '14px "Courier New"';
    ctx.fillStyle = 'rgba(0, 255, 136, 0.7)';
    ctx.fillText(player.name, canvas.width / 4, 80);

    // VS
    ctx.font = 'bold 20px "Courier New"';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.fillText('VS', canvas.width / 2, 50);

    // AI1分数
    ctx.font = 'bold 36px "Courier New"';
    ctx.shadowColor = ai1.color;
    ctx.shadowBlur = 15;
    ctx.fillStyle = ai1.color;
    ctx.fillText(ai1.score, canvas.width * 3 / 4 - 50, 50);
    ctx.shadowBlur = 0;

    ctx.font = '12px "Courier New"';
    ctx.fillStyle = 'rgba(255, 68, 102, 0.7)';
    ctx.fillText(ai1.name, canvas.width * 3 / 4 - 50, 68);

    // AI2分数
    ctx.font = 'bold 36px "Courier New"';
    ctx.shadowColor = ai2.color;
    ctx.shadowBlur = 15;
    ctx.fillStyle = ai2.color;
    ctx.fillText(ai2.score, canvas.width * 3 / 4 + 50, 50);
    ctx.shadowBlur = 0;

    ctx.font = '12px "Courier New"';
    ctx.fillStyle = 'rgba(255, 170, 0, 0.7)';
    ctx.fillText(ai2.name, canvas.width * 3 / 4 + 50, 68);

    // 连击显示
    if (combo > 1 && comboTimer > 0) {
        ctx.font = `bold ${16 + combo * 2}px "Courier New"`;
        const comboAlpha = Math.min(1, comboTimer / 60);
        ctx.fillStyle = `rgba(255, 255, 0, ${comboAlpha})`;
        ctx.fillText(`🔥 ${combo}x COMBO`, canvas.width / 2, canvas.height - 30);
    }

    // 效果指示器
    drawEffectIndicator(player, 80, canvas.height - 20, 'player');
