    drawEffectIndicator(ai2, canvas.width - 60, canvas.height - 20, 'ai2');
}

function drawEffectIndicator(paddle, x, y, key) {
    if (activeEffects[key].timer > 0) {
        const alpha = activeEffects[key].timer > 30 ? 1 : activeEffects[key].timer / 30;
        ctx.font = '12px "Courier New"';
        ctx.textAlign = 'center';
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
        const barWidth = 40;
        const barHeight = 4;
        const progress = activeEffects[key].timer / 300;

        ctx.fillStyle = `rgba(100, 100, 100, ${alpha * 0.5})`;
        ctx.fillRect(x - barWidth / 2, y, barWidth, barHeight);
        ctx.fillStyle = `rgba(255, 255, 0, ${alpha})`;
        ctx.fillRect(x - barWidth / 2, y, barWidth * progress, barHeight);

        ctx.fillStyle = `rgba(255, 255, 255, ${alpha * 0.8})`;
        ctx.fillText(activeEffects[key].type, x, y - 5);
    }
}

function drawPowerups() {
    powerups.forEach(p => {
        const pulse = Math.sin(p.pulse) * 3;

        // 外圈发光
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.radius + pulse + 5, 0, Math.PI * 2);
        ctx.fillStyle = p.color.replace(')', ', 0.1)').replace('rgb', 'rgba');
        ctx.fill();

        // 主体
        ctx.shadowColor = p.color;
        ctx.shadowBlur = 15;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.radius + pulse, 0, Math.PI * 2);
        ctx.fillStyle = p.color.replace(')', ', 0.3)').replace('rgb', 'rgba');
        ctx.strokeStyle = p.color;
        ctx.lineWidth = 2;
        ctx.fill();
        ctx.stroke();
