    ctx.shadowBlur = 30;
    ctx.fillStyle = winner.includes('玩家') ? '#00ff88' : '#ff4466';
    ctx.fillText(winner, canvas.width / 2, canvas.height / 2 - 40);
    ctx.shadowBlur = 0;

    ctx.font = '24px "Courier New"';
    ctx.fillStyle = '#aaaacc';
    ctx.fillText(`${player.name}: ${player.score}  |  ${ai1.name}: ${ai1.score}  |  ${ai2.name}: ${ai2.score}`, canvas.width / 2, canvas.height / 2 + 20);

    const blinkAlpha = Math.sin(time * 3) * 0.5 + 0.5;
    ctx.globalAlpha = blinkAlpha;
    ctx.font = '20px "Courier New"';
    ctx.fillStyle = '#ffffff';
    ctx.fillText('点击或按空格重新开始', canvas.width / 2, canvas.height / 2 + 70);
    ctx.globalAlpha = 1;
}

function drawPaused() {
    ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.font = 'bold 36px "Courier New"';
    ctx.textAlign = 'center';
    ctx.fillStyle = '#ffffff';
    ctx.fillText('⏸ 暂停', canvas.width / 2, canvas.height / 2);

    ctx.font = '16px "Courier New"';
    ctx.fillStyle = '#aaaaaa';
    ctx.fillText('按 P 继续', canvas.width / 2, canvas.height / 2 + 35);
}

function draw() {
    ctx.save();
    ctx.translate(screenShake.x, screenShake.y);

    if (gameState === 'menu') {
        drawMenu();
    } else {
        drawField();

        // 挡板
        drawGlowRect(player.x, player.y, player.width, player.height, player.color, player.glowColor);
        drawGlowRect(ai1.x, ai1.y, ai1.width, ai1.height, ai1.color, ai1.glowColor);
        drawGlowRect(ai2.x, ai2.y, ai2.width, ai2.height, ai2.color, ai2.glowColor);

        // AI标签
        ctx.font = '10px "Courier New"';
        ctx.textAlign = 'center';
        ctx.fillStyle = ai1.color;
        ctx.fillText('α', ai1.x + ai1.width / 2, ai1.y - 5);
        ctx.fillStyle = ai2.color;
        ctx.fillText('β', ai2.x + ai2.width / 2, ai2.y - 5);

        // 道具
        drawPowerups();

        // 球
        drawBall();

        // 粒子
        drawParticles();

        // 浮动文字
        drawFloatingTexts();

        // 记分板
        drawScoreboard();

        // 速度指示器
        const speed = Math.sqrt(ball.speedX ** 2 + ball.speedY ** 2);
        ctx.font = '10px "Courier New"';
        ctx.textAlign = 'right';
        ctx.fillStyle = `rgba(255, 255, 255, 0.3)`;
        ctx.fillText(`SPD: ${speed.toFixed(1)}`, canvas.width - 10, canvas.height - 10);

        if (gameState === 'gameover') drawGameOver();
        if (gameState === 'paused') drawPaused();
    }

    ctx.restore();
}

function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
}

gameLoop();
</script>
