function predictBallY(paddle, ballObj) {
    if (ballObj.speedX <= 0 && paddle.x > canvas.width / 2) return ballObj.y;
    if (ballObj.speedX >= 0 && paddle.x < canvas.width / 2) return ballObj.y;

    let simX = ballObj.x;
    let simY = ballObj.y;
    let simVX = ballObj.speedX;
    let simVY = ballObj.speedY;

    let steps = 0;
    while (steps < 200) {
        simX += simVX;
        simY += simVY;

        if (simY <= ballObj.radius || simY >= canvas.height - ballObj.radius) {
            simVY = -simVY;
        }

        if ((paddle.x > canvas.width / 2 && simX >= paddle.x) ||
            (paddle.x < canvas.width / 2 && simX <= paddle.x + paddle.width)) {
            return simY;
        }
        steps++;
    }
    return canvas.height / 2;
}

function updateAI(aiPaddle, ballObj) {
