        const speed = Math.min(Math.sqrt(ballObj.speedX ** 2 + ballObj.speedY ** 2) + 0.3, ball.maxSpeed);

        if (isPlayer) {
            ballObj.speedX = Math.abs(Math.cos(angle) * speed);
        } else {
            ballObj.speedX = -Math.abs(Math.cos(angle) * speed);
        }
        ballObj.speedY = Math.sin(angle) * speed;

        // 确保球不卡在挡板里
        if (isPlayer) {
            ballObj.x = paddle.x + paddle.width + ballObj.radius;
        } else {
            ballObj.x = paddle.x - ballObj.radius;
