    // 挡板碰撞
    checkPaddleCollision(player, ball, true);

    // AI挡板碰撞 - 检测哪个AI更近
    const ai1Dist = Math.abs(ball.y - (ai1.y + ai1.height / 2));
    const ai2Dist = Math.abs(ball.y - (ai2.y + ai2.height / 2));

    if (!checkPaddleCollision(ai1, ball, false)) {
        checkPaddleCollision(ai2, ball, false);
    }

    // 道具碰撞检测
    powerups.forEach((p, index) => {
        if (p.collected) return;
        const dx = ball.x - p.x;
        const dy = ball.y - p.y;
        if (Math.sqrt(dx * dx + dy * dy) < ball.radius + p.radius) {
            p.collected = true;
            createParticles(p.x, p.y, p.color, 25, 8);
            createFloatingText(p.x, p.y - 20, p.type.toUpperCase() + '!', p.color, 24);

            // 应用效果给最后击球的人
            let target = lastHitter === '玩家' ? 'player' : 
                         lastHitter === 'AI-α' ? 'ai1' : 'ai2';

            applyPowerup(target, p.type);
        }
    });
    powerups = powerups.filter(p => !p.collected);

    // 道具生成
    powerupTimer++;
    if (powerupTimer >= POWERUP_INTERVAL) {
        powerupTimer = 0;
        if (powerups.length < 3) createPowerup();
    }

    // 更新道具动画
    powerups.forEach(p => {
        p.pulse += 0.05;
    });

    // 更新效果计时器
    for (let key in activeEffects) {
        if (activeEffects[key].timer > 0) {
            activeEffects[key].timer--;
            if (activeEffects[key].timer <= 0) {
                removePowerup(key, activeEffects[key].type);
                activeEffects[key].type = null;
            }
        }
    }

    // 得分判定
    if (ball.x < -20) {
        // AI得分 - 两个AI各得1分
        ai1.score++;
        ai2.score++;
        createParticles(0, ball.y, '#ff4466', 30, 10);
        createFloatingText(canvas.width / 4, canvas.height / 2, 'AI 得分!', '#ff4466', 30);
        screenShake.intensity = 8;
        checkGameOver();
        if (gameState === 'playing') resetBall();
    }
    if (ball.x > canvas.width + 20) {
        // 玩家得分
        player.score += 2;
        createParticles(canvas.width, ball.y, '#00ff88', 30, 10);
        createFloatingText(canvas.width * 3 / 4, canvas.height / 2, '得分 +2!', '#00ff88', 30);
        screenShake.intensity = 8;
        checkGameOver();
        if (gameState === 'playing') resetBall();
    }

    // 连击计时器
    if (comboTimer > 0) comboTimer--;
    if (comboTimer <= 0) combo = 0;

    // 更新粒子
    particles.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.life -= p.decay;
        p.vx *= 0.98;
        p.vy *= 0.98;
    });
    particles = particles.filter(p => p.life > 0);

    // 更新浮动文字
    floatingTexts.forEach(t => {
        t.y += t.vy;
        t.life -= 0.015;
    });
    floatingTexts = floatingTexts.filter(t => t.life > 0);

    // 更新屏幕震动
    if (screenShake.intensity > 0) {
        screenShake.x = (Math.random() - 0.5) * screenShake.intensity;
        screenShake.y = (Math.random() - 0.5) * screenShake.intensity;
        screenShake.intensity *= 0.9;
        if (screenShake.intensity < 0.5) {
            screenShake.intensity = 0;
            screenShake.x = 0;
            screenShake.y = 0;
        }
    }

    // 更新星星
    stars.forEach(s => {
        s.brightness = 0.3 + Math.sin(Date.now() * 0.001 * s.speed + s.x) * 0.7;
    });
}

function applyPowerup(target, type) {
    const paddle = target === 'player' ? player : target === 'ai1' ? ai1 : ai2;

    // 移除之前的效果
    if (activeEffects[target].type) {
        removePowerup(target, activeEffects[target].type);
    }

    activeEffects[target] = { type: type, timer: 300 };

    switch (type) {
        case 'speed':
            paddle.speed *= 1.5;
            break;
        case 'big':
            paddle.height *= 1.5;
            break;
        case 'slow':
            // 减慢对手
            if (target === 'player') {
                ai1.speed *= 0.6;
                ai2.speed *= 0.6;
            } else {
                player.speed *= 0.6;
            }
            break;
        case 'multi':
            ball.speedX *= 1.3;
            ball.speedY *= 1.3;
            break;
    }
}

function removePowerup(target, type) {
    const paddle = target === 'player' ? player : target === 'ai1' ? ai1 : ai2;

    switch (type) {
        case 'speed':
            paddle.speed = target === 'player' ? 7 : target === 'ai1' ? 4.5 : 5.2;
            break;
        case 'big':
            paddle.height = target === 'player' ? 100 : 80;
            paddle.y = Math.min(paddle.y, canvas.height - paddle.height);
            break;
        case 'slow':
            if (target === 'player') {
                ai1.speed = 4.5;
                ai2.speed = 5.2;
            } else {
                player.speed = 7;
            }
            break;
    }
}

function checkGameOver() {
    const winScore = 15;
    if (player.score >= winScore) {
        gameState = 'gameover';
        winner = '🏆 玩家获胜！';
    } else if (ai1.score >= winScore || ai2.score >= winScore) {
        gameState = 'gameover';
        if (ai1.score > ai2.score) winner = '💀 AI-α 获胜！';
        else if (ai2.score > ai1.score) winner = '💀 AI-β 获胜！';
        else winner = '💀 AI联盟获胜！';
    }
}

function drawGlowRect(x, y, w, h, color, glowColor) {
    ctx.shadowColor = color;
    ctx.shadowBlur = 20;
    ctx.fillStyle = glowColor;
    ctx.fillRect(x - 3, y - 3, w + 6, h + 6);
    ctx.shadowBlur = 0;

    ctx.fillStyle = color;
    ctx.fillRect(x, y, w, h);

    // 高光
    const gradient = ctx.createLinearGradient(x, y, x + w, y);
    gradient.addColorStop(0, 'rgba(255,255,255,0.3)');
    gradient.addColorStop(1, 'rgba(255,255,255,0)');
    ctx.fillStyle = gradient;
    ctx.fillRect(x, y, w, h);
}

function drawBall() {
    // 轨迹
    ball.trail.forEach((t, i) => {
        const alpha = i / ball.trail.length * 0.5;
        const size = ball.radius * (i / ball.trail.length);
        ctx.beginPath();
        ctx.arc(t.x, t.y, size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
        ctx.fill();
    });

    // 球本体发光
    ctx.shadowColor = '#ffffff';
    ctx.shadowBlur = 25;
    ctx.beginPath();
    ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
    ctx.fillStyle = '#ffffff';
    ctx.fill();
    ctx.shadowBlur = 0;

    // 球内部渐变
    const grad = ctx.createRadialGradient(ball.x - 2, ball.y - 2, 0, ball.x, ball.y, ball.radius);
    grad.addColorStop(0, '#ffffff');
    grad.addColorStop(1, '#aaddff');
    ctx.beginPath();
    ctx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
}

function drawField() {
    // 背景渐变
    const bgGrad = ctx.createRadialGradient(canvas.width / 2, canvas.height / 2, 0, canvas.width / 2, canvas.height / 2, canvas.width / 2);
    bgGrad.addColorStop(0, '#0d1b3e');
    bgGrad.addColorStop(1, '#050a1a');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 星空
    stars.forEach(s => {
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(200, 220, 255, ${s.brightness * 0.5})`;
        ctx.fill();
    });

    // 中线
    ctx.setLineDash([10, 10]);
    ctx.strokeStyle = 'rgba(100, 150, 255, 0.2)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(canvas.width / 2, 0);
    ctx.lineTo(canvas.width / 2, canvas.height);
    ctx.stroke();
    ctx.setLineDash([]);

    // 右侧AI区域分隔线
    ctx.setLineDash([5, 15]);
    ctx.strokeStyle = 'rgba(255, 100, 100, 0.15)';
    ctx.beginPath();
    ctx.moveTo(canvas.width / 2, canvas.height / 2);
    ctx.lineTo(canvas.width, canvas.height / 2);
    ctx.stroke();
    ctx.setLineDash([]);

    // 中心圆
    ctx.beginPath();
    ctx.arc(canvas.width / 2, canvas.height / 2, 50, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(100, 150, 255, 0.15)';
    ctx.lineWidth = 1;
    ctx.stroke();
}

function drawScoreboard() {
    // 玩家分数
    ctx.font = 'bold 48px "Courier New"';
    ctx.textAlign = 'center';

    ctx.shadowColor = player.color;
    ctx.shadowBlur = 15;
    ctx.fillStyle = player.color;
    ctx.fillText(player.score, canvas.width / 4, 60);
    ctx.shadowBlur = 0;

    ctx.font = '14px "Courier New"';
    ctx.fillStyle = 'rgba(0, 255, 136, 0.7)';
    ctx.fillText(player.name, canvas.width / 4, 80);

    // VS
    ctx.font = 'bold 20px "Courier New"';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.fillText('VS', canvas.width / 2, 50);

    // AI1分数
    ctx.font = 'bold 36px "Courier New"';
    ctx.shadowColor = ai1.color;
    ctx.shadowBlur = 15;
    ctx.fillStyle = ai1.color;
    ctx.fillText(ai1.score, canvas.width * 3 / 4 - 50, 50);
    ctx.shadowBlur = 0;

    ctx.font = '12px "Courier New"';
    ctx.fillStyle = 'rgba(255, 68, 102, 0.7)';
    ctx.fillText(ai1.name, canvas.width * 3 / 4 - 50, 68);

    // AI2分数
    ctx.font = 'bold 36px "Courier New"';
    ctx.shadowColor = ai2.color;
    ctx.shadowBlur = 15;
    ctx.fillStyle = ai2.color;
    ctx.fillText(ai2.score, canvas.width * 3 / 4 + 50, 50);
    ctx.shadowBlur = 0;

    ctx.font = '12px "Courier New"';
    ctx.fillStyle = 'rgba(255, 170, 0, 0.7)';
    ctx.fillText(ai2.name, canvas.width * 3 / 4 + 50, 68);

    // 连击显示
    if (combo > 1 && comboTimer > 0) {
        ctx.font = `bold ${16 + combo * 2}px "Courier New"`;
        const comboAlpha = Math.min(1, comboTimer / 60);
        ctx.fillStyle = `rgba(255, 255, 0, ${comboAlpha})`;
        ctx.fillText(`🔥 ${combo}x COMBO`, canvas.width / 2, canvas.height - 30);
    }

    // 效果指示器
    drawEffectIndicator(player, 80, canvas.height - 20, 'player');
    drawEffectIndicator(ai1, canvas.width - 120, canvas.height - 20, 'ai1');
    drawEffectIndicator(ai2, canvas.width - 60, canvas.height - 20, 'ai2');
}

function drawEffectIndicator(paddle, x, y, key) {
    if (activeEffects[key].timer > 0) {
        const alpha = activeEffects[key].timer > 30 ? 1 : activeEffects[key].timer / 30;
        ctx.font = '12px "Courier New"';
        ctx.textAlign = 'center';
        ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
        const barWidth = 40;
        const barHeight = 4;
        const progress = activeEffects[key].timer / 300;

        ctx.fillStyle = `rgba(100, 100, 100, ${alpha * 0.5})`;
        ctx.fillRect(x - barWidth / 2, y, barWidth, barHeight);
        ctx.fillStyle = `rgba(255, 255, 0, ${alpha})`;
        ctx.fillRect(x - barWidth / 2, y, barWidth * progress, barHeight);

        ctx.fillStyle = `rgba(255, 255, 255, ${alpha * 0.8})`;
        ctx.fillText(activeEffects[key].type, x, y - 5);
    }
}

function drawPowerups() {
    powerups.forEach(p => {
        const pulse = Math.sin(p.pulse) * 3;

        // 外圈发光
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.radius + pulse + 5, 0, Math.PI * 2);
        ctx.fillStyle = p.color.replace(')', ', 0.1)').replace('rgb', 'rgba');
        ctx.fill();

        // 主体
        ctx.shadowColor = p.color;
        ctx.shadowBlur = 15;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.radius + pulse, 0, Math.PI * 2);
        ctx.fillStyle = p.color.replace(')', ', 0.3)').replace('rgb', 'rgba');
        ctx.strokeStyle = p.color;
        ctx.lineWidth = 2;
        ctx.fill();
        ctx.stroke();
        ctx.shadowBlur = 0;

        // 标签
        ctx.font = '16px sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillStyle = '#ffffff';
        ctx.fillText(p.label, p.x, p.y);
        ctx.textBaseline = 'alphabetic';
    });
}

function drawParticles() {
    particles.forEach(p => {
        ctx.globalAlpha = p.life;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
        ctx.fillStyle = p.color;
        ctx.fill();
    });
    ctx.globalAlpha = 1;
}

function drawFloatingTexts() {
    floatingTexts.forEach(t => {
        ctx.globalAlpha = t.life;
        ctx.font = `bold ${t.size}px "Courier New"`;
        ctx.textAlign = 'center';
        ctx.fillStyle = t.color;
        ctx.shadowColor = t.color;
        ctx.shadowBlur = 10;
        ctx.fillText(t.text, t.x, t.y);
        ctx.shadowBlur = 0;
    });
    ctx.globalAlpha = 1;
}

function drawMenu() {
    drawField();

    // 标题
    const time = Date.now() * 0.001;
    const titleY = canvas.height / 2 - 80 + Math.sin(time * 2) * 5;

    ctx.font = 'bold 42px "Courier New"';
    ctx.textAlign = 'center';
    ctx.shadowColor = '#00ffff';
    ctx.shadowBlur = 30;
    ctx.fillStyle = '#00ffff';
    ctx.fillText('⚡ 双AI乒乓大战 ⚡', canvas.width / 2, titleY);
    ctx.shadowBlur = 0;

    ctx.font = '18px "Courier New"';
    ctx.fillStyle = '#88aacc';
    ctx.fillText('1 vs 2 — 你能打败两个AI吗？', canvas.width / 2, titleY + 40);

    // 角色介绍
    ctx.font = '14px "Courier New"';
    ctx.fillStyle = player.color;
    ctx.fillText(`${player.name} — W/S 或鼠标控制`, canvas.width / 2, titleY + 80);
    ctx.fillStyle = ai1.color;
    ctx.fillText(`${ai1.name} — 稳健型AI`, canvas.width / 2, titleY + 105);
    ctx.fillStyle = ai2.color;
    ctx.fillText(`${ai2.name} — 激进型AI`, canvas.width / 2, titleY + 130);

    // 开始提示
    const blinkAlpha = Math.sin(time * 3) * 0.5 + 0.5;
    ctx.globalAlpha = blinkAlpha;
    ctx.font = 'bold 22px "Courier New"';
    ctx.fillStyle = '#ffffff';
    ctx.fillText('点击或按 空格/回车 开始', canvas.width / 2, titleY + 180);
    ctx.globalAlpha = 1;

    ctx.font = '12px "Courier New"';
    ctx.fillStyle = 'rgba(150, 150, 200, 0.6)';
    ctx.fillText('先到15分获胜 | P键暂停 | 收集道具获得增益', canvas.width / 2, canvas.height - 30);
}

function drawGameOver() {
    // 半透明覆盖
    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const time = Date.now() * 0.001;

    ctx.font = 'bold 48px "Courier New"';
    ctx.textAlign = 'center';
    ctx.shadowColor = winner.includes('玩家') ? '#00ff88' : '#ff4466';
    ctx.shadowBlur = 30;
    ctx.fillStyle = winner.includes('玩家') ? '#00ff88' : '#ff4466';
    ctx.fillText(winner, canvas.width / 2, canvas.height / 2 - 40);
    ctx.shadowBlur = 0;

    ctx.font = '24px "Courier New"';
    ctx.fillStyle = '#aaaacc';
    ctx.fillText(`${player.name}: ${player.score}  |  ${ai1.name}: ${ai1.score}  |  ${ai2.name}: ${ai2.score}`, canvas.width / 2, canvas.height / 2 + 20);

    const blinkAlpha = Math.sin(time * 3) * 0.5 + 0.5;
    ctx.globalAlpha = blinkAlpha;
    ctx.font = '20px "Courier New"';
    ctx.fillStyle = '#ffffff';
    ctx.fillText('点击或按空格重新开始', canvas.width / 2, canvas.height / 2 + 70);
    ctx.globalAlpha = 1;
}

function drawPaused() {
    ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.font = 'bold 36px "Courier New"';
    ctx.textAlign = 'center';
    ctx.fillStyle = '#ffffff';
    ctx.fillText('⏸ 暂停', canvas.width / 2, canvas.height / 2);

    ctx.font = '16px "Courier New"';
    ctx.fillStyle = '#aaaaaa';
    ctx.fillText('按 P 继续', canvas.width / 2, canvas.height / 2 + 35);
}

function draw() {
    ctx.save();
    ctx.translate(screenShake.x, screenShake.y);

    if (gameState === 'menu') {
        drawMenu();
    } else {
        drawField();

        // 挡板
        drawGlowRect(player.x, player.y, player.width, player.height, player.color, player.glowColor);
        drawGlowRect(ai1.x, ai1.y, ai1.width, ai1.height, ai1.color, ai1.glowColor);
        drawGlowRect(ai2.x, ai2.y, ai2.width, ai2.height, ai2.color, ai2.glowColor);

        // AI标签
        ctx.font = '10px "Courier New"';
        ctx.textAlign = 'center';
        ctx.fillStyle = ai1.color;
        ctx.fillText('α', ai1.x + ai1.width / 2, ai1.y - 5);
        ctx.fillStyle = ai2.color;
        ctx.fillText('β', ai2.x + ai2.width / 2, ai2.y - 5);

        // 道具
        drawPowerups();

        // 球
        drawBall();

        // 粒子
        drawParticles();

        // 浮动文字
        drawFloatingTexts();

        // 记分板
        drawScoreboard();

        // 速度指示器
        const speed = Math.sqrt(ball.speedX ** 2 + ball.speedY ** 2);
        ctx.font = '10px "Courier New"';
        ctx.textAlign = 'right';
        ctx.fillStyle = `rgba(255, 255, 255, 0.3)`;
        ctx.fillText(`SPD: ${speed.toFixed(1)}`, canvas.width - 10, canvas.height - 10);

        if (gameState === 'gameover') drawGameOver();
        if (gameState === 'paused') drawPaused();
    }

    ctx.restore();
}

function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
}

gameLoop();
</script>
</body>
</html>
